; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6, 7, 8, 9]

;-------------------------------------------------------------------------------
*event_1
;[exp] inSearching || onObjectTrigger
*event_2
;[exp] inSearching || onObjectTrigger
*event_3
;[exp] inSearching || onObjectTrigger
*event_4
;[exp] inSearching || onObjectTrigger

[if exp='! game.inSearching']
	@notice text="There is a pedestal with a large crystal ball at the top."
	[eventoff]
[endif]

@delevent
@se f=period
@changefloor pimg="lighten"
@notice text="<y>The crystal ball began to glow!"

[if exp='! game.map.events.has(1) && ! game.map.events.has(2) && ! game.map.events.has(3) && ! game.map.events.has(4)']
	@wait time=800
	@se f=fence
	@switchfence map=常闇の城３Ｆ x=6 y=2 way=n mode=open
	@notice text="I heard a door open somewhere!"
[endif]

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] inSearching

@notice text="There is a ladder to the lower floor but it appears to be broken."

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("power", 1)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Strength permanently increased by 1!"'

[eventoff]
;-------------------------------------------------------------------------------
